import{_ as a}from"./chunks/global-char-part.Dg_kBqt-.js";import{_ as e,o,c as n,a2 as r}from"./chunks/framework.CkaEw-3u.js";const u=JSON.parse('{"title":"Core Concepts","description":"","frontmatter":{"title":"Core Concepts","head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/en/guide/core-concepts.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Core Concepts | Mug Typography Manual"}],["meta",{"property":"og:description","content":"Online manual for Mug Typography, a DaVinci Resolve OFX plugin that dissects text into independently animated parts"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/en/guide/core-concepts.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"property":"og:image:type","content":"image/jpeg"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"Core Concepts | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"Online manual for Mug Typography, a DaVinci Resolve OFX plugin that dissects text into independently animated parts"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"en/guide/core-concepts.md","filePath":"en/guide/core-concepts.md"}'),s={name:"en/guide/core-concepts.md"};function i(p,t,c,l,d,h){return o(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h1><p>This plugin has <strong>three levels</strong> that you can work with.</p><table tabindex="0"><thead><tr><th>Level</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Global</strong></td><td>Settings applied to the entire text at once</td><td>Font, overall position, rotation, and scale</td></tr><tr><td><strong>Character</strong></td><td>Settings that can be applied individually to each character</td><td>Enlarge a specific character or change its color</td></tr><tr><td><strong>Part</strong></td><td>Settings for each path element that makes up a character</td><td>Move only the diacritic marks in a character</td></tr></tbody></table><p>For example, you can move the entire text to the right globally, shift only a specific character farther upward, and rotate only a particular part within that character.</p><h2 id="how-transformations-accumulate" tabindex="-1">How Transformations Accumulate <a class="header-anchor" href="#how-transformations-accumulate" aria-label="Permalink to &quot;How Transformations Accumulate&quot;">​</a></h2><p>Transformations at each level accumulate in the order Global → Character → Part, and the result is rendered.</p><div class="propagation-formula"><div class="propagation-term"><span class="propagation-symbol">M<sub>Global</sub></span><span class="propagation-value">Rotation +10°</span><small>Around the pivot of the entire text</small></div><span class="propagation-op">×</span><div class="propagation-term"><span class="propagation-symbol">M<sub>Character</sub></span><span class="propagation-value">Rotation +15°</span><small>Then around the character&#39;s pivot</small></div><span class="propagation-op">×</span><div class="propagation-term"><span class="propagation-symbol">M<sub>Part</sub></span><span class="propagation-value">Rotation +20°</span><small>And then around the part&#39;s pivot</small></div><span class="propagation-op propagation-op-eq">＝</span><div class="propagation-term propagation-term-result"><span class="propagation-symbol">M<sub>Final</sub></span><span class="propagation-value">Orientation +45°</span><small>The orientation totals 45°, while the rendered position depends on the relative locations of the pivots and is not a simple sum</small></div><div class="propagation-demo"><div class="propagation-orbit" aria-hidden="true"><span class="propagation-ring propagation-ring-g"></span><span class="propagation-sun"></span><div class="propagation-system-g"><div class="propagation-earth-system"><span class="propagation-ring propagation-ring-c"></span><span class="propagation-earth"></span><div class="propagation-system-c"><span class="propagation-moon"></span></div></div></div></div><div class="propagation-orbit-copy"><ul class="propagation-legend"><li><span class="propagation-legend-dot propagation-legend-sun"></span>Sun = Global (entire text)</li><li><span class="propagation-legend-dot propagation-legend-earth"></span>Earth = Character (each character)</li><li><span class="propagation-legend-dot propagation-legend-moon"></span>Moon = Part (each part)</li></ul><p class="propagation-demo-caption">The Earth revolves around the Sun, and the Moon revolves around the Earth. Just as the Moon&#39;s position and orientation as seen from the Sun are determined by both rotations, Global, Character, and Part transformations are multiplied in sequence around the pivot at each level. Therefore, although the rotation angles can be added together, the final position is not a simple sum.</p></div></div></div><p><img src="'+a+'" alt="Transformations being added at the Global, Character, and Part levels"></p><p><em>Transformations accumulating in the order Global → Character → Part</em></p><p>Color composition follows the same order of precedence. For details, see &quot;<a href="/mug-typography-docs/en/reference/appendix.html#color-priority">Color Priority</a>&quot; in the appendix.</p><h2 id="when-part-controls-are-not-needed" tabindex="-1">When Part Controls Are Not Needed <a class="header-anchor" href="#when-part-controls-are-not-needed" aria-label="Permalink to &quot;When Part Controls Are Not Needed&quot;">​</a></h2><p>If you do not need part-level controls such as movement or scaling, selecting a Lite version makes clip loading and selection more responsive. This is because Part Settings are omitted from the Inspector, reducing the number of controls.</p><p>It is important to choose the preset that suits your purpose. For details, see &quot;<a href="/mug-typography-docs/en/guide/getting-started.html">Getting Started</a>&quot;.</p><h2 id="understanding-the-indices" tabindex="-1">Understanding the Indices <a class="header-anchor" href="#understanding-the-indices" aria-label="Permalink to &quot;Understanding the Indices&quot;">​</a></h2><p><code>Character 1, 2...</code> in Character Settings indicates the character number counted from the beginning of the input text. <code>Part Setting 1, 2...</code> in Part Settings indicates the part number across all characters. These correspond to <code>c1</code> and <code>p1</code> used in Targets under Output Settings and Animation Settings.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Each item in the Inspector displays the actual character and the part&#39;s position within that character. If the numbers alone are difficult to interpret, select the target in the viewer and check the corresponding item.</p></div><hr><p><a id="interface-overview-ja"></a></p>',18)])])}const y=e(s,[["render",i]]);export{u as __pageData,y as default};
